class Solution:
    def resultingString(self, s: str) -> str:
        stack = []
        for char in s:
            if stack and ord(stack[-1]) == ord(char) - 1 or stack and ord(stack[-1]) == ord('z') - ord(char) + 1:
                stack.pop()
            else:
                stack.append(char)
        return ''.join(stack)
```

